import * as util from "../core/util.js";

const error = () => {
    // Hebrew labels + grammatical gender
    const TypeNames = {
        NaN: { gender: "m", label: "NaN" },
        array: { gender: "m", label: "מערך" },
        bigint: { gender: "m", label: "BigInt" },
        boolean: { gender: "m", label: "ערך בוליאני" },
        date: { gender: "m", label: "תאריך" },
        file: { gender: "m", label: "קובץ" },
        function: { gender: "f", label: "פונקציה" },
        map: { gender: "f", label: "מפה (Map)" },
        null: { gender: "m", label: "ערך ריק (null)" },
        number: { gender: "m", label: "מספר" },
        object: { gender: "m", label: "אובייקט" },
        promise: { gender: "m", label: "Promise" },
        set: { gender: "f", label: "קבוצה (Set)" },
        string: { gender: "f", label: "מחרוזת" },
        symbol: { gender: "m", label: "סימבול (Symbol)" },
        undefined: { gender: "m", label: "ערך לא מוגדר (undefined)" },
        unknown: { gender: "m", label: "ערך לא ידוע" },
        value: { gender: "m", label: "ערך" },
    };
    // Sizing units for size-related messages + localized origin labels
    const Sizable = {
        array: { longLabel: "גדול", shortLabel: "קטן", unit: "פריטים" },
        file: { longLabel: "גדול", shortLabel: "קטן", unit: "בייטים" },
        number: { longLabel: "גדול", shortLabel: "קטן", unit: "" }, // no unit
        set: { longLabel: "גדול", shortLabel: "קטן", unit: "פריטים" },
        string: { longLabel: "ארוך", shortLabel: "קצר", unit: "תווים" },
    };
    // Helpers — labels, articles, and verbs
    const typeEntry = (t) => (t ? TypeNames[t] : undefined);
    const typeLabel = (t) => {
        const e = typeEntry(t);
        if (e)
            {return e.label;}
        // fallback: show raw string if unknown
        return t ?? TypeNames.unknown.label;
    };
    const withDefinite = (t) => `ה${typeLabel(t)}`;
    const verbFor = (t) => {
        const e = typeEntry(t);
        const gender = e?.gender ?? "m";
        return gender === "f" ? "צריכה להיות" : "צריך להיות";
    };
    const getSizing = (origin) => {
        if (!origin)
            {return null;}
        return Sizable[origin] ?? null;
    };
    const FormatDictionary = {
        base64: { gender: "f", label: "מחרוזת בבסיס 64" },
        base64url: { gender: "f", label: "מחרוזת בבסיס 64 לכתובות רשת" },
        cidrv4: { gender: "m", label: "טווח IPv4" },
        cidrv6: { gender: "m", label: "טווח IPv6" },
        cuid: { gender: "m", label: "cuid" },
        cuid2: { gender: "m", label: "cuid2" },
        date: { gender: "m", label: "תאריך ISO" },
        datetime: { gender: "m", label: "תאריך וזמן ISO" },
        duration: { gender: "m", label: "משך זמן ISO" },
        e164: { gender: "m", label: "מספר E.164" },
        email: { gender: "f", label: "כתובת אימייל" },
        emoji: { gender: "m", label: "אימוג'י" },
        ends_with: { gender: "m", label: "קלט" },
        guid: { gender: "m", label: "GUID" },
        includes: { gender: "m", label: "קלט" },
        ipv4: { gender: "f", label: "כתובת IPv4" },
        ipv6: { gender: "f", label: "כתובת IPv6" },
        json_string: { gender: "f", label: "מחרוזת JSON" },
        jwt: { gender: "m", label: "JWT" },
        ksuid: { gender: "m", label: "KSUID" },
        lowercase: { gender: "m", label: "קלט" },
        nanoid: { gender: "m", label: "nanoid" },
        regex: { gender: "m", label: "קלט" },
        starts_with: { gender: "m", label: "קלט" },
        time: { gender: "m", label: "זמן ISO" },
        ulid: { gender: "m", label: "ULID" },
        uppercase: { gender: "m", label: "קלט" },
        url: { gender: "f", label: "כתובת רשת" },
        uuid: { gender: "m", label: "UUID" },
        xid: { gender: "m", label: "XID" },
    };
    const TypeDictionary = {
        nan: "NaN",
    };
    return (issue) => {
        switch (issue.code) {
            case "invalid_type": {
                // Expected type: show without definite article for clearer Hebrew
                const expectedKey = issue.expected;
                const expected = TypeDictionary[expectedKey ?? ""] ?? typeLabel(expectedKey);
                // Received: show localized label if known, otherwise constructor/raw
                const receivedType = util.parsedType(issue.input);
                const received = TypeDictionary[receivedType] ?? TypeNames[receivedType]?.label ?? receivedType;
                if (/^[A-Z]/.test(issue.expected)) {
                    return `קלט לא תקין: צריך להיות instanceof ${issue.expected}, התקבל ${received}`;
                }
                return `קלט לא תקין: צריך להיות ${expected}, התקבל ${received}`;
            }
            case "invalid_value": {
                if (issue.values.length === 1) {
                    return `ערך לא תקין: הערך חייב להיות ${util.stringifyPrimitive(issue.values[0])}`;
                }
                // Join values with proper Hebrew formatting
                const stringified = issue.values.map((v) => util.stringifyPrimitive(v));
                if (issue.values.length === 2) {
                    return `ערך לא תקין: האפשרויות המתאימות הן ${stringified[0]} או ${stringified[1]}`;
                }
                // For 3+ values: "a", "b" או "c"
                const lastValue = stringified.at(-1);
                const restValues = stringified.slice(0, -1).join(", ");
                return `ערך לא תקין: האפשרויות המתאימות הן ${restValues} או ${lastValue}`;
            }
            case "too_big": {
                const sizing = getSizing(issue.origin);
                const subject = withDefinite(issue.origin ?? "value");
                if (issue.origin === "string") {
                    // Special handling for strings - more natural Hebrew
                    return `${sizing?.longLabel ?? "ארוך"} מדי: ${subject} צריכה להכיל ${issue.maximum.toString()} ${sizing?.unit ?? ""} ${issue.inclusive ? "או פחות" : "לכל היותר"}`.trim();
                }
                if (issue.origin === "number") {
                    // Natural Hebrew for numbers
                    const comparison = issue.inclusive ? `קטן או שווה ל-${issue.maximum}` : `קטן מ-${issue.maximum}`;
                    return `גדול מדי: ${subject} צריך להיות ${comparison}`;
                }
                if (issue.origin === "array" || issue.origin === "set") {
                    // Natural Hebrew for arrays and sets
                    const verb = issue.origin === "set" ? "צריכה" : "צריך";
                    const comparison = issue.inclusive
                        ? `${issue.maximum} ${sizing?.unit ?? ""} או פחות`
                        : `פחות מ-${issue.maximum} ${sizing?.unit ?? ""}`;
                    return `גדול מדי: ${subject} ${verb} להכיל ${comparison}`.trim();
                }
                const adj = issue.inclusive ? "<=" : "<";
                const be = verbFor(issue.origin ?? "value");
                if (sizing?.unit) {
                    return `${sizing.longLabel} מדי: ${subject} ${be} ${adj}${issue.maximum.toString()} ${sizing.unit}`;
                }
                return `${sizing?.longLabel ?? "גדול"} מדי: ${subject} ${be} ${adj}${issue.maximum.toString()}`;
            }
            case "too_small": {
                const sizing = getSizing(issue.origin);
                const subject = withDefinite(issue.origin ?? "value");
                if (issue.origin === "string") {
                    // Special handling for strings - more natural Hebrew
                    return `${sizing?.shortLabel ?? "קצר"} מדי: ${subject} צריכה להכיל ${issue.minimum.toString()} ${sizing?.unit ?? ""} ${issue.inclusive ? "או יותר" : "לפחות"}`.trim();
                }
                if (issue.origin === "number") {
                    // Natural Hebrew for numbers
                    const comparison = issue.inclusive ? `גדול או שווה ל-${issue.minimum}` : `גדול מ-${issue.minimum}`;
                    return `קטן מדי: ${subject} צריך להיות ${comparison}`;
                }
                if (issue.origin === "array" || issue.origin === "set") {
                    // Natural Hebrew for arrays and sets
                    const verb = issue.origin === "set" ? "צריכה" : "צריך";
                    // Special case for singular (minimum === 1)
                    if (issue.minimum === 1 && issue.inclusive) {
                        const singularPhrase = issue.origin === "set" ? "לפחות פריט אחד" : "לפחות פריט אחד";
                        return `קטן מדי: ${subject} ${verb} להכיל ${singularPhrase}`;
                    }
                    const comparison = issue.inclusive
                        ? `${issue.minimum} ${sizing?.unit ?? ""} או יותר`
                        : `יותר מ-${issue.minimum} ${sizing?.unit ?? ""}`;
                    return `קטן מדי: ${subject} ${verb} להכיל ${comparison}`.trim();
                }
                const adj = issue.inclusive ? ">=" : ">";
                const be = verbFor(issue.origin ?? "value");
                if (sizing?.unit) {
                    return `${sizing.shortLabel} מדי: ${subject} ${be} ${adj}${issue.minimum.toString()} ${sizing.unit}`;
                }
                return `${sizing?.shortLabel ?? "קטן"} מדי: ${subject} ${be} ${adj}${issue.minimum.toString()}`;
            }
            case "invalid_format": {
                const _issue = issue;
                // These apply to strings — use feminine grammar + ה׳ הידיעה
                if (_issue.format === "starts_with")
                    {return `המחרוזת חייבת להתחיל ב "${_issue.prefix}"`;}
                if (_issue.format === "ends_with")
                    {return `המחרוזת חייבת להסתיים ב "${_issue.suffix}"`;}
                if (_issue.format === "includes")
                    {return `המחרוזת חייבת לכלול "${_issue.includes}"`;}
                if (_issue.format === "regex")
                    {return `המחרוזת חייבת להתאים לתבנית ${_issue.pattern}`;}
                // Handle gender agreement for formats
                const nounEntry = FormatDictionary[_issue.format];
                const noun = nounEntry?.label ?? _issue.format;
                const gender = nounEntry?.gender ?? "m";
                const adjective = gender === "f" ? "תקינה" : "תקין";
                return `${noun} לא ${adjective}`;
            }
            case "not_multiple_of": {
                return `מספר לא תקין: חייב להיות מכפלה של ${issue.divisor}`;
            }
            case "unrecognized_keys": {
                return `מפתח${issue.keys.length > 1 ? "ות" : ""} לא מזוה${issue.keys.length > 1 ? "ים" : "ה"}: ${util.joinValues(issue.keys, ", ")}`;
            }
            case "invalid_key": {
                return `שדה לא תקין באובייקט`;
            }
            case "invalid_union": {
                return "קלט לא תקין";
            }
            case "invalid_element": {
                const place = withDefinite(issue.origin ?? "array");
                return `ערך לא תקין ב${place}`;
            }
            default: {
                return `קלט לא תקין`;
            }
        }
    };
};
export default function () {
    return {
        localeError: error(),
    };
}
