import * as util from "../core/util.js";

const error = () => {
    const Sizable = {
        array: { subject: "listan", unit: "alkiota" },
        bigint: { subject: "suuren kokonaisluvun", unit: "" },
        date: { subject: "päivämäärän", unit: "" },
        file: { subject: "tiedoston", unit: "tavua" },
        int: { subject: "kokonaisluvun", unit: "" },
        number: { subject: "luvun", unit: "" },
        set: { subject: "joukon", unit: "alkiota" },
        string: { subject: "merkkijonon", unit: "merkkiä" },
    };
    function getSizing(origin) {
        return Sizable[origin] ?? null;
    }
    const FormatDictionary = {
        base64: "base64-koodattu merkkijono",
        base64url: "base64url-koodattu merkkijono",
        cidrv4: "IPv4-alue",
        cidrv6: "IPv6-alue",
        cuid: "cuid",
        cuid2: "cuid2",
        date: "ISO-päivämäärä",
        datetime: "ISO-aikaleima",
        duration: "ISO-kesto",
        e164: "E.164-luku",
        email: "sähköpostiosoite",
        emoji: "emoji",
        guid: "GUID",
        ipv4: "IPv4-osoite",
        ipv6: "IPv6-osoite",
        json_string: "JSON-merkkijono",
        jwt: "JWT",
        ksuid: "KSUID",
        nanoid: "nanoid",
        regex: "säännöllinen lauseke",
        template_literal: "templaattimerkkijono",
        time: "ISO-aika",
        ulid: "ULID",
        url: "URL-osoite",
        uuid: "UUID",
        uuidv4: "UUIDv4",
        uuidv6: "UUIDv6",
        xid: "XID",
    };
    const TypeDictionary = {
        nan: "NaN",
    };
    return (issue) => {
        switch (issue.code) {
            case "invalid_type": {
                const expected = TypeDictionary[issue.expected] ?? issue.expected;
                const receivedType = util.parsedType(issue.input);
                const received = TypeDictionary[receivedType] ?? receivedType;
                if (/^[A-Z]/.test(issue.expected)) {
                    return `Virheellinen tyyppi: odotettiin instanceof ${issue.expected}, oli ${received}`;
                }
                return `Virheellinen tyyppi: odotettiin ${expected}, oli ${received}`;
            }
            case "invalid_value": {
                if (issue.values.length === 1)
                    {return `Virheellinen syöte: täytyy olla ${util.stringifyPrimitive(issue.values[0])}`;}
                return `Virheellinen valinta: täytyy olla yksi seuraavista: ${util.joinValues(issue.values, "|")}`;
            }
            case "too_big": {
                const adj = issue.inclusive ? "<=" : "<";
                const sizing = getSizing(issue.origin);
                if (sizing) {
                    return `Liian suuri: ${sizing.subject} täytyy olla ${adj}${issue.maximum.toString()} ${sizing.unit}`.trim();
                }
                return `Liian suuri: arvon täytyy olla ${adj}${issue.maximum.toString()}`;
            }
            case "too_small": {
                const adj = issue.inclusive ? ">=" : ">";
                const sizing = getSizing(issue.origin);
                if (sizing) {
                    return `Liian pieni: ${sizing.subject} täytyy olla ${adj}${issue.minimum.toString()} ${sizing.unit}`.trim();
                }
                return `Liian pieni: arvon täytyy olla ${adj}${issue.minimum.toString()}`;
            }
            case "invalid_format": {
                const _issue = issue;
                if (_issue.format === "starts_with")
                    {return `Virheellinen syöte: täytyy alkaa "${_issue.prefix}"`;}
                if (_issue.format === "ends_with")
                    {return `Virheellinen syöte: täytyy loppua "${_issue.suffix}"`;}
                if (_issue.format === "includes")
                    {return `Virheellinen syöte: täytyy sisältää "${_issue.includes}"`;}
                if (_issue.format === "regex") {
                    return `Virheellinen syöte: täytyy vastata säännöllistä lauseketta ${_issue.pattern}`;
                }
                return `Virheellinen ${FormatDictionary[_issue.format] ?? issue.format}`;
            }
            case "not_multiple_of": {
                return `Virheellinen luku: täytyy olla luvun ${issue.divisor} monikerta`;
            }
            case "unrecognized_keys": {
                return `${issue.keys.length > 1 ? "Tuntemattomat avaimet" : "Tuntematon avain"}: ${util.joinValues(issue.keys, ", ")}`;
            }
            case "invalid_key": {
                return "Virheellinen avain tietueessa";
            }
            case "invalid_union": {
                return "Virheellinen unioni";
            }
            case "invalid_element": {
                return "Virheellinen arvo joukossa";
            }
            default: {
                return `Virheellinen syöte`;
            }
        }
    };
};
export default function () {
    return {
        localeError: error(),
    };
}
